+.filter-chip:hover,
+.filter-chip.active {
+    background: var(--color-primary);
+    border-color: var(--color-primary);
+    color: white;
+}
+
+/* Search Results */
+.search-results {
+    display: flex;
+    flex-direction: column;
+    gap: var(--space-md);
+}
+
+.result-card {
+    background: var(--color-bg-card);
+    border: 1px solid var(--color-border);
+    border-radius: var(--radius-lg);
+    padding: var(--space-lg);
+    cursor: pointer;
+    transition: var(--transition-fast);
+}
+
+.result-card:hover {
+    border-color: var(--color-primary);
+    box-shadow: var(--shadow-md);
+}
+
+.result-header {
+    display: flex;
+    align-items: center;
+    justify-content: space-between;
+    margin-bottom: var(--space-sm);
+}
+
+.result-title {
+    font-weight: 600;
+    color: var(--color-text);
+}
+
+.result-agent {
+    font-size: 0.75rem;
+    padding: var(--space-xs) var(--space-sm);
+    background: var(--color-bg-input);
+    border-radius: var(--radius-sm);
+    color: var(--color-text-muted);
+}
+
+.result-snippet {
+    font-size: 0.9375rem;
+    color: var(--color-text-muted);
+    line-height: 1.6;
+}
+
+.result-snippet mark {
+    background: rgba(59, 130, 246, 0.3);
+    color: var(--color-text);
+    padding: 0 2px;
+    border-radius: 2px;
+}
+
+.result-meta {
+    display: flex;
+    gap: var(--space-md);
+    margin-top: var(--space-sm);
+    font-size: 0.8125rem;
+    color: var(--color-text-dim);
+}
+
+/* ========================================
+   Conversation Viewer (populated by conversation.js)
+   ======================================== */
+.conversation-container {
+    max-width: 900px;
+    margin: 0 auto;
+}
+
+.conversation-header {
+    display: flex;
+    align-items: center;
+    gap: var(--space-md);
+    margin-bottom: var(--space-lg);
+    padding-bottom: var(--space-lg);
+    border-bottom: 1px solid var(--color-border);
+}
+
+.back-btn {
+    width: 2.5rem;
+    height: 2.5rem;
+    border-radius: var(--radius-md);
+    border: 1px solid var(--color-border);
+    background: transparent;
+    color: var(--color-text);
+    font-size: 1.25rem;
+    cursor: pointer;
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    transition: var(--transition-fast);
+}
+
+.back-btn:hover {
+    background: var(--color-bg-hover);
+}
+
+.conversation-title {
+    flex: 1;
+}
+
+.conversation-title h2 {
+    font-size: 1.25rem;
+    font-weight: 600;
+}
+
+.conversation-title .meta {
+    font-size: 0.8125rem;
+    color: var(--color-text-muted);
+}
+
+.messages-list {
+    display: flex;
+    flex-direction: column;
+    gap: var(--space-lg);
+}
+
+.message {
+    background: var(--color-bg-card);
+    border: 1px solid var(--color-border);
+    border-radius: var(--radius-lg);
+    overflow: hidden;
+}
+
+.message-header {
+    display: flex;
+    align-items: center;
+    gap: var(--space-sm);
+    padding: var(--space-md);
+    background: var(--color-bg-input);
+    border-bottom: 1px solid var(--color-border);
+}
+
+.message-role {
+    font-weight: 600;
+    font-size: 0.875rem;
+}
+
+.message-role.user {
+    color: var(--color-primary);
+}
+
+.message-role.assistant {
+    color: var(--color-success);
+}
+
+.message-time {
+    font-size: 0.75rem;
+    color: var(--color-text-dim);
+    margin-left: auto;
+}
+
+.message-content {
+    padding: var(--space-lg);
+    font-size: 0.9375rem;
+    line-height: 1.7;
+}
+
+.message-content p {
+    margin-bottom: var(--space-md);
+}
+
+.message-content p:last-child {
+    margin-bottom: 0;
+}
+
+/* Code blocks */
+.message-content pre {
+    background: var(--color-bg);
+    border: 1px solid var(--color-border);
+    border-radius: var(--radius-md);
+    padding: var(--space-md);
+    overflow-x: auto;
+    margin: var(--space-md) 0;
+}
+
+.message-content code {
+    font-family: var(--font-mono);
+    font-size: 0.875rem;
+}
+
+.message-content :not(pre) > code {
+    background: var(--color-bg-input);
+    padding: 2px 6px;
+    border-radius: var(--radius-sm);
+}
+
+/* ========================================
+   Responsive Design
+   ======================================== */
+@media (max-width: 640px) {
+    .auth-card {
+        padding: var(--space-lg);
+    }
+
+    .auth-header .logo {
+        font-size: 2.5rem;
+    }
+
+    .auth-header h1 {
+        font-size: 1.5rem;
+    }
+
+    .btn {
+        padding: var(--space-md);
+    }
+
+    .fingerprint {
+        flex-wrap: wrap;
+        text-align: center;
+    }
+
+    .search-box {
+        flex-direction: column;
+    }
+
+    .result-header {
+        flex-direction: column;
+        align-items: flex-start;
+        gap: var(--space-sm);
+    }
+
+    .conversation-header {
+        flex-wrap: wrap;
+    }
+}
+
+/* ========================================
+   Print Styles
+   ======================================== */
+@media print {
+    .auth-container,
+    .app-header,
+    .search-box,
+    .search-filters,
+    .back-btn,
+    .btn {
+        display: none !important;
+    }
+
+    .app-container,
+    .conversation-container {
+        padding: 0;
+    }
+
+    .message {
+        break-inside: avoid;
+        border: 1px solid #ccc;
+    }
+
+    .message-content pre {
+        white-space: pre-wrap;
+    }
+}
+
+/* ========================================
+   Accessibility
+   ======================================== */
+@media (prefers-reduced-motion: reduce) {
+    *,
+    *::before,
+    *::after {
+        animation-duration: 0.01ms !important;
+        animation-iteration-count: 1 !important;
+        transition-duration: 0.01ms !important;
+    }
+}
+
+/* Focus visible for keyboard navigation */
+:focus-visible {
+    outline: 2px solid var(--color-primary);
+    outline-offset: 2px;
+}
+
+button:focus:not(:focus-visible),
+input:focus:not(:focus-visible) {
+    outline: none;
+}
